#nullable enable // autogenerated

using MVZ2.Vanilla.Detections;
using PVZEngine.Entities;
using UnityEngine;

namespace MVZ2.GameContent.Detections
{
    public class BoxDetector : Detector
    {
        public BoxDetector(Vector3 size, Vector3 offset, bool canDetectInvisible = false)
        {
            this.size = size;
            this.offset = offset;
            this.pivot = new Vector3(0.5f, 0, 0.5f);
            this.canDetectInvisible = canDetectInvisible;
        }
        public BoxDetector(Vector3 size, Vector3 offset, Vector3 pivot, bool canDetectInvisible = false)
        {
            this.size = size;
            this.offset = offset;
            this.pivot = pivot;
            this.canDetectInvisible = canDetectInvisible;
        }
        protected override Bounds GetDetectionBounds(Entity self)
        {
            var center = self.Position;
            center -= Vector3.Scale(pivot - Vector3.one * 0.5f, size);
            center += offset;
            return new Bounds(center, size);
        }
        public Vector3 size;
        public Vector3 offset;
        public Vector3 pivot;
    }
}
